import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.Toast;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;
import java.security.KeyStore;
import java.util.concurrent.Executor;
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;

public class LoginActivity extends AppCompatActivity {
    private static final String PREFS_NAME = "BiometricAuthPrefs";
    private static final String KEY_BIOMETRIC_ENABLED = "biometric_enabled";
    private static final String KEY_USER_AUTHENTICATED = "user_authenticated";
    private static final String KEY_USERNAME = "username";
    private static final String ANDROID_KEYSTORE = "AndroidKeyStore";
    private static final String KEY_NAME = "BiometricAuthKey";
    
    private EditText usernameEditText;
    private EditText passwordEditText;
    private Button loginButton;
    private CheckBox biometricCheckBox;
    private Button biometricLoginButton;
    
    private BiometricPrompt biometricPrompt;
    private BiometricPrompt.PromptInfo promptInfo;
    private Executor executor;
    private SharedPreferences sharedPreferences;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);
        
        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        
        initializeViews();
        setupBiometricAuthentication();
        
        if (isBiometricEnabled() && canAuthenticateWithBiometrics()) {
            biometricLoginButton.setEnabled(true);
            showBiometricPrompt();
        }
        
        loginButton.setOnClickListener(v -> handlePasswordLogin());
        biometricLoginButton.setOnClickListener(v -> showBiometricPrompt());
    }
    
    private void initializeViews() {
        usernameEditText = findViewById(R.id.usernameEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        loginButton = findViewById(R.id.loginButton);
        biometricCheckBox = findViewById(R.id.biometricCheckBox);
        biometricLoginButton = findViewById(R.id.biometricLoginButton);
        
        biometricCheckBox.setChecked(isBiometricEnabled());
        biometricLoginButton.setEnabled(false);
    }
    
    private void setupBiometricAuthentication() {
        executor = ContextCompat.getMainExecutor(this);
        
        biometricPrompt = new BiometricPrompt(this, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                Toast.makeText(LoginActivity.this, "Authentication error: " + errString, Toast.LENGTH_SHORT).show();
            }
            
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                handleBiometricSuccess();
            }
            
            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                Toast.makeText(LoginActivity.this, "Authentication failed", Toast.LENGTH_SHORT).show();
            }
        });
        
        promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Biometric Authentication")
                .setSubtitle("Log in using your fingerprint")
                .setNegativeButtonText("Use password")
                .setConfirmationRequired(true)
                .build();
    }
    
    private boolean canAuthenticateWithBiometrics() {
        BiometricManager biometricManager = BiometricManager.from(this);
        int canAuthenticate = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG);
        
        switch (canAuthenticate) {
            case BiometricManager.BIOMETRIC_SUCCESS:
                return true;
            case BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE:
                Toast.makeText(this, "No biometric hardware available", Toast.LENGTH_SHORT).show();
                return false;
            case BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE:
                Toast.makeText(this, "Biometric hardware unavailable", Toast.LENGTH_SHORT).show();
                return false;
            case BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED:
                Toast.makeText(this, "No biometric credentials enrolled", Toast.LENGTH_SHORT).show();
                return false;
            default:
                return false;
        }
    }
    
    private void handlePasswordLogin() {
        String username = usernameEditText.getText().toString().trim();
        String password = passwordEditText.getText().toString().trim();
        
        if (username.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Please enter username and password", Toast.LENGTH_SHORT).show();
            return;
        }
        
        if (validateCredentials(username, password)) {
            saveAuthenticationState(username);
            
            if (biometricCheckBox.isChecked() && canAuthenticateWithBiometrics()) {
                enableBiometricAuthentication();
            } else {
                disableBiometricAuthentication();
            }
            
            navigateToMainActivity();
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
        }
    }
    
    private boolean validateCredentials(String username, String password) {
        return username.equals("demo") && password.equals("password123");
    }
    
    private void showBiometricPrompt() {
        if (canAuthenticateWithBiometrics()) {
            try {
                Cipher cipher = getCipher();
                SecretKey secretKey = getOrCreateSecretKey();
                cipher.init(Cipher.ENCRYPT_MODE, secretKey);
                BiometricPrompt.CryptoObject cryptoObject = new BiometricPrompt.CryptoObject(cipher);
                biometricPrompt.authenticate(promptInfo, cryptoObject);
            } catch (Exception e) {
                Toast.makeText(this, "Biometric authentication setup failed", Toast.LENGTH_SHORT).show();
                biometricPrompt.authenticate(promptInfo);
            }
        }
    }
    
    private void handleBiometricSuccess() {
        Toast.makeText(this, "Biometric authentication successful", Toast.LENGTH_SHORT).show();
        navigateToMainActivity();
    }
    
    private void saveAuthenticationState(String username) {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putBoolean(KEY_USER_AUTHENTICATED, true);
        editor.putString(KEY_USERNAME, username);
        editor.apply();
    }
    
    private void enableBiometricAuthentication() {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putBoolean(KEY_BIOMETRIC_ENABLED, true);
        editor.apply();
    }
    
    private void disableBiometricAuthentication() {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putBoolean(KEY_BIOMETRIC_ENABLED, false);
        editor.apply();
    }
    
    private boolean isBiometricEnabled() {
        return sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false);
    }
    
    private void navigateToMainActivity() {
        Intent intent = new Intent(this, MainActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }
    
    private SecretKey getOrCreateSecretKey() throws Exception {
        KeyStore keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
        keyStore.load(null);
        
        if (keyStore.containsAlias(KEY_NAME)) {
            return (SecretKey) keyStore.getKey(KEY_NAME, null);
        }
        
        KeyGenerator keyGenerator = KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE);
        
        KeyGenParameterSpec keyGenParameterSpec = new KeyGenParameterSpec.Builder(
                KEY_NAME,
                KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                .setBlockModes(KeyProperties.BLOCK_MODE_CBC)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_PKCS7)
                .setUserAuthenticationRequired(true)
                .setInvalidatedByBiometricEnrollment(true)
                .build();
        
        keyGenerator.init(keyGenParameterSpec);
        return keyGenerator.generateKey();
    }
    
    private Cipher getCipher() throws Exception {
        return Cipher.getInstance(
                KeyProperties.KEY_ALGORITHM_AES + "/"
                        + KeyProperties.BLOCK_MODE_CBC + "/"
                        + KeyProperties.ENCRYPTION_PADDING_PKCS7);
    }
}